parameters.jsCode:
const response = $input.first().json;
const config = $('2. Set — Config Values').item.json;

const t = response?.data?.transcript;
if (!t || !t.id) throw new Error('Transcript not found for meetingId: ' + config.meetingId);

const speakers = t.analytics?.speakers || [];

if (speakers.length === 0) {
  throw new Error('No speaker analytics available for this meeting. Fireflies may not have detected speakers.');
}

const threshold = parseInt(config.dominanceThreshold) || 70;
const meetingDurationMin = Math.round((t.duration || 0) / 60);

const meetingDate = t.date
  ? new Date(t.date).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })
  : new Date().toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' });

// Sort speakers by duration_pct descending
const sorted = [...speakers].sort((a, b) =>
  (b.duration_pct || 0) - (a.duration_pct || 0)
);

// Build speaker rows
let speakerLines = '';
let dominatingSpeaker = null;
let totalQuestions = 0;

sorted.forEach((sp, index) => {
  const name = sp.name || 'Speaker ' + (index + 1);
  const pct = Math.round(sp.duration_pct || 0);
  const words = sp.word_count || 0;
  const wpm = Math.round(sp.words_per_minute || 0);
  const questions = sp.questions || 0;
  const longestMono = Math.round((sp.longest_monologue || 0) / 60);
  const monologues = sp.monologues_count || 0;
  const fillers = sp.filler_words || 0;
  const talkMin = Math.round((sp.duration || 0) / 60);

  totalQuestions += questions;

  // Build visual talk bar (10 chars = 100%)
  const barFilled = Math.round(pct / 10);
  const bar = '█'.repeat(barFilled) + '░'.repeat(10 - barFilled);

  // Flag dominant speaker
  const dominanceFlag = pct >= threshold ? ' DOMINANT' : '';
  if (pct >= threshold && !dominatingSpeaker) dominatingSpeaker = name;

  speakerLines +=
    (index + 1) + '. ' + name + dominanceFlag + '\n' +
    '   ' + bar + ' ' + pct + '% (' + talkMin + ' min)\n' +
    '   Words: ' + words + ' | Pace: ' + wpm + ' wpm | Questions: ' + questions + '\n' +
    '   Longest speech: ' + longestMono + ' min | Turns: ' + monologues + ' | Fillers: ' + fillers + '\n\n';
});

// Build alert message
let alertLine = '';
if (dominatingSpeaker) {
  alertLine = 'ALERT: ' + dominatingSpeaker + ' dominated this meeting at ' +
    Math.round(sorted[0].duration_pct || 0) + '% talk time. Consider giving others more space.\n\n';
} else {
  alertLine = 'Balance: Talk time was reasonably distributed across participants.\n\n';
}

// Build full Telegram message
const message =
  'Meeting Talk-Time Report\n' +
  '\n' +
  'Meeting: ' + (t.title || 'Untitled') + '\n' +
  'Date: ' + meetingDate + ' | Duration: ' + meetingDurationMin + ' min\n' +
  'Total Questions Asked: ' + totalQuestions + '\n' +
  '\n' +
  alertLine +
  'SPEAKER BREAKDOWN\n\n' +
  speakerLines +
  'Fireflies: ' + (t.transcript_url || 'Not available');

return [{
  json: {
    telegramMessage: message,
    telegramChatId: config.telegramChatId,
    hasDominance: !!dominatingSpeaker,
    meetingTitle: t.title || 'Untitled'
  }
}];
